// 1. Destructuring -- unpack values from objects and arrays
const { name, age, ...rest } = { name: 'Alice', age: 30, role: 'dev', active: true };
// name = 'Alice', age = 30, rest = { role: 'dev', active: true }

const [first, , third] = [10, 20, 30];
// first = 10, third = 30 (skipped second)

// 2. Spread operator -- copy and merge
const defaults = { theme: 'light', lang: 'en' };
const userPrefs = { theme: 'dark' };
const settings = { ...defaults, ...userPrefs };
// { theme: 'dark', lang: 'en' } -- later spreads override

// 3. Optional chaining -- safely access nested properties
const city = user?.address?.city; // undefined if any part is null/undefined
const firstFriend = user?.friends?.[0];
const result = user?.getName?.();

// 4. Nullish coalescing -- default only for null/undefined
const port = process.env.PORT ?? 3000;
// '' ?? 3000 -> '' (empty string is NOT nullish)
// 0  ?? 3000 -> 0  (zero is NOT nullish)
// null ?? 3000 -> 3000

// 5. Object shorthand
const x = 10, y = 20;
const point = { x, y }; // same as { x: x, y: y }

// 6. Computed property names
const field = 'email';
const formData = { [field]: 'alice@example.com' };
// { email: 'alice@example.com' }

// 7. for...of loop (iterates over values, not indices)
for (const fruit of ['apple', 'banana', 'cherry']) {
  console.log(fruit);
}

// 8. Map and Set
const uniqueTags = new Set(['react', 'js', 'react', 'css']);
// Set { 'react', 'js', 'css' } -- duplicates removed

const cache = new Map();
cache.set('user:1', { name: 'Alice' });
cache.get('user:1'); // { name: 'Alice' }
cache.has('user:1'); // true
